INSERT INTO `posts` VALUES (3,2,'다중파일 업로드 테스트','3개 넣어 보장~',17,'2026-02-03 15:15:49','2026-02-03 15:26:15'),(4,2,'pdf 업로드 테스트','pdf도 테스트 해보자!',20,'2026-02-03 15:17:25','2026-02-04 15:09:22'),(5,14,'귀여움 (수정)','강아지 최고\r\n고양이도 최고',15,'2026-02-03 15:20:01','2026-02-04 15:09:24'),(6,12,'파이썬 21일차 공부내용','파이썬 공부내용',6,'2026-02-03 15:20:04','2026-02-03 15:23:40'),(7,23,'안녕(수정)','귀욤댕이 강쥐보세여~~~\r\n안넝',13,'2026-02-03 15:20:23','2026-02-03 15:24:54'),(8,24,'로그인 화면 이미지 파일<뚜정>','예뿌당 호호호호',18,'2026-02-03 15:20:29','2026-03-05 15:33:18'),(9,13,'괭','고양이',7,'2026-02-03 15:20:32','2026-02-03 15:22:38'),(10,21,'자료등록화면','자료등록화면',12,'2026-02-03 15:20:34','2026-02-20 14:19:28'),(11,3,'HTML공부','HTML공부',10,'2026-02-03 15:20:55','2026-03-05 15:33:16'),(12,27,'크리스탈','펭귄아님 이었음',17,'2026-02-03 15:21:01','2026-02-20 14:19:23'),(13,26,'자료등록 테스트','테스트',10,'2026-02-03 15:21:28','2026-03-05 15:33:13'),(14,3,'HTML','26.02.03 연습',16,'2026-02-03 15:22:19','2026-02-03 15:25:12'),(15,19,'.','너구리',5,'2026-02-03 15:22:23','2026-02-04 15:09:39'),(16,18,'HTML','\r\n태그(Tag): 브라우저에게 \"이 데이터는 무엇이다\"라고 알려주는 명령어입니다.\r\n\r\n시맨틱(Semantic): 의미가 명확한 태그(<nav>, <article>)를 쓰는 것이 좋은 코드입니다.\r\n\r\n속성(Attribute): 태그 옆에 붙는 설정값(<a href=\"...\">)으로 기능을 확장합니다.\r\n1. 구조 설계 (Layout)\r\n웹페이지의 구역을 나누는 큰 틀입니다.\r\n<header> : 페이지 최상단 (로고, 메인 메뉴 구역)\r\n<nav>    : 내비게이션 (메뉴, 링크 모음 구역)\r\n<main>   : 페이지의 핵심 본문 내용 (페이지당 한 번만 사용)\r\n<section>: 본문 내의 큰 주제별 구역\r\n<article>: 독립적인 콘텐츠 (블로그 글, 뉴스 기사)\r\n<aside>  : 사이드바 (본문 옆의 부가 정보)\r\n<footer> : 페이지 최하단 (저작권, 주소, 연락처)\r\n<div>    : 아무 의미 없는 범용 박스 (단순히 묶을 때 사용)\r\n\r\n2. 텍스트 표현 (Text)\r\n화면에 글자를 출력하고 강조하는 요소입니다.\r\n    <h1>~<h6>: 제목 (숫자가 작을수록 크고 중요한 제목)\r\n<p>      : 문단 (일반적인 텍스트 덩어리)\r\n<span>   : 문장 내 특정 부분만 감싸는 용도 (디자인용)\r\n<a>      : 하이퍼링크 (클릭 시 페이지 이동)\r\n<strong> : 글자 굵게 강조 (중요한 내용)\r\n<em>     : 글자 기울임 강조 (강조하고 싶은 내용)\r\n<br>     : 강제 줄바꿈 (닫는 태그 없음)\r\n<hr>     : 수평 구분선 (닫는 태그 없음)\r\n\r\n 3. 목록 생성 (List)\r\n 데이터를 나열할 때 사용하는 자료구조형 태그입니다.\r\n<ul> : 순서가 없는 목록 (불렛 포인트)\r\n<ol> : 순서가 있는 목록 (1, 2, 3 번호)\r\n<li> : 목록 내부의 각 개별 항목\r\n\r\n 4. 사용자 입력 (Forms)\r\n사용자의 데이터를 받는 인터페이스입니다.\r\n<form>    : 입력된 데이터를 서버로 전달하는 전체 묶음\r\n<input>   : 글자 입력, 체크박스 등 다양한 입력창 (닫는 태그 없음)\r\n<label>   : 입력창(input)에 붙이는 이름표\r\n<textarea>: 여러 줄을 입력할 수 있는 넓은 입력창\r\n<select>  : 드롭다운 선택 목록\r\n<button>  : 클릭 가능한 실행 버튼\r\n\r\n 5. 미디어 및 표 (Media & Table)\r\n시각적인 정보나 표 형식을 나타냅니다.\r\n<img>  : 이미지 출력 (닫는 태그 없음)\r\n<table>: 표 전체 틀\r\n<tr>   : 표의 한 행 (가로줄)\r\n<th>   : 표의 제목 칸 (굵게 표시됨)\r\n<td>   : 표의 일반 데이터 칸\r\n-->',12,'2026-02-03 15:24:12','2026-02-20 14:19:18'),(18,11,'다중파일 수정','다중파일 수정',9,'2026-02-03 15:33:18','2026-03-05 15:33:07'),(19,54,'파일 첨부 테스트','다중 파일 업로드',1,'2026-02-12 12:57:07','2026-03-05 15:33:09'),(20,59,'파일첨부 테스트요','다중파일 업로드 해볼게염',2,'2026-02-12 12:57:21','2026-03-05 15:33:11'),(21,59,'파일첨부 테스트요','다중파일 업로드 해볼게염',5,'2026-02-12 13:00:21','2026-03-11 17:31:29'),(22,2,'11','11',3,'2026-02-20 14:19:35','2026-03-11 17:31:27');
